request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT
  ?rel
  ?relType
  ?contrib
  ?contribType
  ?contribName
WHERE {
  BIND(
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::10%2520Analysis::Roll-up%2520Analyses::Error%2520Budgets::Pupil%2520Alignment%2520Error%2520Budget>
    AS ?budget
  )

  VALUES ?relType { vocab:satisfy vocab:verify vocab:allocate vocab:dependency vocab:conform }

  {
    ?rel rdf:type ?relType ;
         vocab:Dependency_supplier ?contrib .
    FILTER(?rel = ?rel)
  }
  UNION
  {
    ?rel rdf:type ?relType ;
         vocab:Dependency_client ?contrib .
    FILTER(?rel = ?rel)
  }
  UNION
  {
    ?rel rdf:type ?relType ;
         vocab:DirectedRelationship_source ?contrib .
  }
  UNION
  {
    ?rel rdf:type ?relType ;
         vocab:DirectedRelationship_target ?contrib .
  }

  # link the relationship to the budget
  {
    ?rel vocab:dependency_supplier ?budget .
  }
  UNION
  {
    ?rel vocab:Dependency_client ?budget .
  }
  UNION
  {
    ?rel vocab:DirectedRelationship_source ?budget .
  }
  UNION
  {
    ?rel vocab:DirectedRelationship_target ?budget .
  }

  OPTIONAL { ?contrib rdf:type ?contribType . }
  OPTIONAL { ?contrib vocab:NamedElement_name ?contribName . }
}
LIMIT 25
